import SwiftUI
enum FamiliarStyle:String,CaseIterable,Identifiable,Codable{case fantasy,retro,darkFantasy,anime;var id:String{rawValue};var name:String{switch self{case .fantasy:"Fantasy";case .retro:"Retro";case .darkFantasy:"Dark Fantasy";case .anime:"Anime"}};var world:String{switch self{case .fantasy:"Moonlit Grove";case .retro:"Verdant Circuit";case .darkFantasy:"The Hollow Keep";case .anime:"Skyflower Valley"}};var accent:Color{switch self{case .fantasy:.orange;case .retro:.yellow;case .darkFantasy:.purple;case .anime:.pink}};var background:Color{switch self{case .fantasy:Color(red:0.03,green:0.13,blue:0.13);case .retro:Color(red:0.08,green:0.18,blue:0.16);case .darkFantasy:Color(red:0.06,green:0.04,blue:0.11);case .anime:Color(red:0.65,green:0.84,blue:0.98)}};var dialogue:String{switch self{case .fantasy:"The grove is listening.";case .retro:"READY! Let’s make this run count.";case .darkFantasy:"Even the long night yields to us.";case .anime:"We’ve got this—together!"}}}
